import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useMusic } from '../../context/MusicContext'; // Import để phát nhạc
import { Play, Trash2, Music, ArrowLeft, Clock, MoreHorizontal } from 'lucide-react';

const PlaylistDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { playMusic } = useMusic(); // Lấy hàm phát nhạc từ context
  
  const [playlist, setPlaylist] = useState(null);
  const [loading, setLoading] = useState(true);
  const loggedInUser = JSON.parse(localStorage.getItem('user'));

  useEffect(() => {
    fetchPlaylist();
  }, [id]);

  const fetchPlaylist = async () => {
    try {
      const res = await axios.get(`http://localhost:5000/api/playlists/${id}`);
      setPlaylist(res.data);
    } catch (err) {
      console.error("Lỗi tải playlist:", err);
    } finally {
      setLoading(false);
    }
  };

  // 1. Phát nhạc từ playlist
  const handlePlayFromPlaylist = (index) => {
    if (playlist.songs && playlist.songs.length > 0) {
      playMusic(playlist.songs, index);
    }
  };

  // 2. Bỏ bài hát khỏi playlist
  const handleRemoveSong = async (e, songId) => {
    e.stopPropagation(); // Ngăn chặn sự kiện phát nhạc khi nhấn nút xóa
    if (!window.confirm("Bạn muốn bỏ bài hát này khỏi danh sách phát?")) return;
    try {
      await axios.put(`http://localhost:5000/api/playlists/${id}/remove`, { songId });
      setPlaylist({
        ...playlist,
        songs: playlist.songs.filter(s => s._id !== songId)
      });
    } catch (err) {
      alert("Không thể xóa bài hát khỏi playlist");
    }
  };

  // 3. Xóa hoàn toàn playlist
  const handleDeletePlaylist = async () => {
    if (!window.confirm("Bạn có chắc chắn muốn xóa vĩnh viễn Playlist này?")) return;
    try {
      await axios.delete(`http://localhost:5000/api/playlists/${id}`);
      alert("Đã xóa playlist!");
      navigate('/');
    } catch (err) {
      alert("Lỗi khi xóa playlist");
    }
  };

  if (loading) return <div style={centerStyle}>Đang tải nội dung...</div>;
  if (!playlist) return <div style={centerStyle}>Không tìm thấy playlist.</div>;

  const isOwner = loggedInUser?._id === playlist.owner?._id || loggedInUser?.id === playlist.owner?._id;

  return (
    <div style={containerStyle}>
      {/* Nút quay lại */}
      <button onClick={() => navigate(-1)} style={backBtnStyle}>
        <ArrowLeft size={20} /> Quay lại
      </button>

      {/* HEADER PLAYLIST */}
      <div style={headerStyle}>
        <div style={playlistImgStyle}>
           <Music size={80} color="#b3b3b3" />
        </div>
        <div style={headerInfoStyle}>
          <span style={labelStyle}>PLAYLIST CỦA TÔI</span>
          <h1 style={titleStyle}>{playlist.title}</h1>
          <div style={metaStyle}>
            <b style={{color: '#fff'}}>{playlist.owner?.username || 'Người dùng'}</b>
            <span style={dotStyle}>•</span>
            <span>{playlist.songs?.length || 0} bài hát</span>
          </div>
        </div>
        {isOwner && (
          <button onClick={handleDeletePlaylist} style={deletePlaylistBtn}>
            Xóa Playlist
          </button>
        )}
      </div>

      {/* DANH SÁCH BÀI HÁT */}
      <div style={listWrapper}>
        <div style={tableHeader}>
          <div style={{ width: '50px' }}>#</div>
          <div style={{ flex: 2 }}>Tiêu đề</div>
          <div style={{ flex: 1 }}>Nghệ sĩ</div>
          <div style={{ width: '100px', textAlign: 'right' }}><Clock size={16} /></div>
        </div>

        {playlist.songs && playlist.songs.length > 0 ? (
          playlist.songs.map((song, index) => (
            <div 
              key={song._id} 
              style={songRowStyle} 
              onClick={() => handlePlayFromPlaylist(index)}
            >
              <div style={indexStyle}>{index + 1}</div>
              
              <div style={songMainInfo}>
                <img 
                  src={`http://localhost:5000${song.imageUrl}`} 
                  alt="" 
                  style={coverStyle}
                  onError={(e) => e.target.src = 'https://via.placeholder.com/40'}
                />
                <div style={textWrapper}>
                  <div style={songTitle}>{song.title}</div>
                  <div style={songArtistSmall}>{song.artist}</div>
                </div>
              </div>

              <div style={artistColumn}>{song.artist}</div>

              <div style={actionColumn}>
                <div className="play-icon" style={miniPlayBtn}>
                  <Play size={16} fill="#1db954" color="#1db954" />
                </div>
                {isOwner && (
                  <button 
                    onClick={(e) => handleRemoveSong(e, song._id)} 
                    style={removeBtn}
                    title="Bỏ khỏi playlist"
                  >
                    <Trash2 size={16} />
                  </button>
                )}
              </div>
            </div>
          ))
        ) : (
          <div style={emptyState}>Hãy quay lại trang chủ để thêm nhạc vào playlist này!</div>
        )}
      </div>
    </div>
  );
};

/* --- STYLES (ĐÃ NÂNG CẤP) --- */
const containerStyle = { padding: '30px 50px', maxWidth: '1200px', margin: '0 auto', color: '#fff', background: 'linear-gradient(to bottom, #2a2a2a, #121212)', minHeight: '100vh' };
const centerStyle = { textAlign: 'center', padding: '100px', color: '#888' };
const backBtnStyle = { display: 'flex', alignItems: 'center', gap: '8px', background: 'none', border: 'none', cursor: 'pointer', marginBottom: '30px', color: '#b3b3b3', fontWeight: 'bold' };

const headerStyle = { display: 'flex', gap: '30px', alignItems: 'flex-end', marginBottom: '40px', position: 'relative' };
const playlistImgStyle = { width: '230px', height: '230px', background: '#282828', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 15px 35px rgba(0,0,0,0.4)', borderRadius: '4px' };
const headerInfoStyle = { flex: 1 };
const labelStyle = { fontSize: '12px', fontWeight: 'bold', letterSpacing: '1px' };
const titleStyle = { fontSize: '72px', margin: '10px 0', fontWeight: '900', letterSpacing: '-2px' };
const metaStyle = { display: 'flex', alignItems: 'center', gap: '10px', color: '#b3b3b3', fontSize: '14px' };
const dotStyle = { fontSize: '20px', lineHeight: '0' };
